// Server-side (ElysiaJS + Bun)
import { Elysia, t } from 'elysia';

const app = new Elysia()
  .ws('/ws', {
    // Extract and verify authentication token
    beforeHandle: ({ headers, set }) => {
      const authHeader = headers.get('Authorization');
      const token = authHeader?.split('Bearer ')[1];

      if (!token) {
        set.status = 401;
        return { error: 'Missing or invalid authorization header' };
      }

      // Verify JWT token (you'd use your JWT library here)
      try {
        const decoded = verifyToken(token); // Implement your verifyToken function
        return { user: decoded }; // Pass user data to handler
      } catch (error) {
        set.status = 401;
        return { error: 'Invalid token' };
      }
    },

    message: ({ user, message }) => {
      console.log(`Message from user ${user.id}:`, message);
      return { echo: message };
    }
  })
  .listen(3000);
```

### 3. **Advanced Authentication Example**

```javascript
// More complete example with JWT verification
import { jwt } from '@elysiajs/jwt';

const app = new Elysia()
  .use(jwt({
    name: 'jwt',
    secret: process.env.JWT_SECRET
  }))
  .ws('/ws', {
    beforeHandle: async ({ jwt, headers, set }) => {
      const authHeader = headers.get('Authorization');
      if (!authHeader?.startsWith('Bearer ')) {
        set.status = 401;
        return { error: 'Missing Bearer token' };
      }

      const token = authHeader.substring(7);
      try {
        const payload = await jwt.verify(token);
        return { user: payload };
      } catch (error) {
        set.status = 401;
        return { error: 'Invalid token' };
      }
    },

    message: ({ user, message, broadcast }) => {
      broadcast(`${user.username}: ${message}`);
      return { status: 'ok' };
    }
  });
```

## Key Points for 2026 Implementation

1. **Bun Runtime**: Bun now has built-in WebSocket support optimized for performance
2. **ElysiaJS**: The preferred framework for Bun, offering excellent TypeScript support and authentication plugins
3. **RFC 6455 Compliance**: WebSocket specification allows Authorization headers during the handshake phase
4. **Security**: Always verify tokens on the server side and use HTTPS/WSS for encrypted connections

## Recommended Setup for 2026

1. Use **ElysiaJS** as your framework (built for Bun)
2. Implement JWT validation using the official `@elysiajs/jwt` plugin
3. Use Bun's built-in WebSocket API for optimal performance
4. Consider rate limiting and connection limits for security

The examples above show both client-side (Node.js/Bun) and server-side (ElysiaJS) implementations for secure WebSocket connections with Bearer token authentication.


